spring.application.name=${APPLICATION_NAME:payment-service}
server.port=${SERVER_PORT:4003}

# gRPC Server Configuration
grpc.server.port=9090
grpc.server.enable-keep-alive=true
grpc.server.keep-alive-time=30s
grpc.server.keep-alive-timeout=5s
grpc.server.permit-keep-alive-without-calls=true

# Sepay Configuration
sepay.account-number=${SEPAY_ACCOUNT_NUMBER}
sepay.bank=${SEPAY_BANK}

# RabbitMQ Configuration
spring.rabbitmq.host=${RABBITMQ_HOST:localhost}
spring.rabbitmq.port=${RABBITMQ_PORT:5672}
spring.rabbitmq.username=${RABBITMQ_USERNAME:guest}
spring.rabbitmq.password=${RABBITMQ_PASSWORD:guest}
spring.rabbitmq.virtual-host=${RABBITMQ_VIRTUAL_HOST:/}
